mapper.select:
SELECT id, household_id, name, category_id, store_id, quantity, threshold
FROM inventory_items
WHERE id = #{id}

mapper.update:
UPDATE inventory_items
SET name = #{name}, category_id = #{categoryId}, store_id = #{storeId}, threshold = #{threshold}
WHERE id = #{id}

UPDATE inventory_items
SET quantity = quantity + #{delta}
WHERE id = #{id}
  AND quantity + #{delta} >= 0
  AND quantity + #{delta} <= 99999.9
